import base64
import os

inscription_b64 = ""
publiclayout_b64 = ""

os.makedirs('src/components', exist_ok=True)

with open('src/components/InscriptionForm.tsx', 'wb') as f:
    f.write(base64.b64decode(inscription_b64))
print("InscriptionForm.tsx ecrit avec succes !")

with open('src/components/PublicLayout.tsx', 'wb') as f:
    f.write(base64.b64decode(publiclayout_b64))
print("PublicLayout.tsx ecrit avec succes !")
